const Q_PHYSICS_2018_MODEL_III=[{"id": "objective>Physics>2018 Model III>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a school compound, a girl walks 40m due east from the laboratory to the staff room to submit her report. Then she turns and walks 30m due north to her classroom. Determine the magnitude of her displacement from the laboratory.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> = 50m <br/>  <img src=\"2018 Model III/k38.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> ∴ the magnitude of her displacement from the laboratory is 50m.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2018 Model III>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following types of lenses is suitable for correcting the eye defect illustrated by the ray diagram above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bi-converging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bi-diverging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plano diverging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diverging meniscus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In eyeglasses and contact lenses, biconvex lenses are used to correct hyperopia (farsightedness) by converging light rays onto the retina.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2018 Model III>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is in a state of unstable equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cone is in unstable equilibrium as a slight displacement will cause it to topple over and not return to its original position.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2018 Model III>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rectangular metal block of volume 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 273k is heated to 573K. If its co-efficient of linear expansivity is 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The percentage of change of its volume is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 273K <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 573K <br/> α = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Δθ = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 300k <br/> % change in volume = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N.B:</td><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> γ = 3α ------ ** <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">change</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> y = 3 × 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 3.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3.6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 300</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 300 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 3.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-91</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">To</td><td style=\"text-align:center;\">change</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.080×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/>  = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × 100 <br/>  = 1.080% <br/>  ≈ 1.1%</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2018 Model III>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is Power?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Force × time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × distance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × velocity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Energy<hr size=\"1\" />Time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">-----------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Force × displacement<hr size=\"1\" />Time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Power</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Force</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">displacement<hr size=\"1\" />time</td></tr></table></div> <br/> Power = Force × velocity</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2018 Model III>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A room which measures 3m x 4m x 5m is cooled from 30°C to 25°C. If the density and specific heat capacity of air are 1.3kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> and 1.0kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> respectively, the amount of heat removed from the room is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">300kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">390kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">780kJ</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volume of the air = 3 × 4 × 5 = 60m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Mass of the air, m = volume × density = 60 × 1.3 = 78kg <br/> Heat removed from the room = mcθ = (78)(1)(30 - 25) <br/>  = 390kJ</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2018 Model III>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Red light travels faster than blue light when both of them pass through a glass prism because the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">refractive index of red light is greater than that of blue light </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refractive index of blue light is greater than that of red light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red light is more intense than the blue light </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue light is more intense than the red light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The refractive index of a medium for a particular wavelength of light is a measure of how much that medium slows down light of that wavelength. Blue light has a shorter wavelength than red light, and so it is slowed down more by a medium (like glass) than red light. Therefore, the refractive index of blue light is greater than that of red light, which is why blue light travels slower than red light in a glass prism.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2018 Model III>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The escape velocity of an object from the gravitational field of a planet <br/> I. increases with the mass of the object <br/> II. increases with the mass of the planet <br/> III. is smaller on the moon than on the earth <br/> Which of the above statements is (are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Escape velocity, v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"> 2Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>&nbsp;</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>&nbsp;</span>, <br/> where m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> and g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are the mass, radius of the planet and acceleration due to gravity on the planet respectively. Note that v is independent of the mass of the object. Also, since g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> and r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are smaller for the moon, v is smaller on the moon.</div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2018 Model III>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not fundamental?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kelvin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steradian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">candella</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mole </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental units of measurement in the International System of Units (SI) are the meter, kilogram, second, ampere, kelvin, mole, and candela. The steradian is not a fundamental unit; it is a derived unit used for measuring solid angles. Therefore, the correct answer is 'steradian'.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2018 Model III>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a beaker of water being heated. It is observed that as the bubbles rise they get bigger in size. The reason for this observation is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water pressure on the bubbles decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">density of water increases with rise in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of water increases with rise in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">atmospheric pressure on the bubbles decreases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atmospheric pressure and water pressure (due to depth) act on the bubble simultaneously, but as the bubble rises water pressure reduces.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2018 Model III>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force is applied at the end Q to a bar PQ pivoted at P (see diagram). The torque produced by the force F about the pivot is greatest when θ is <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If L = length of PQ <br/> Torque about P = L(Fsinθ) = FLsinθ <br/> This is maximum when sinθ = 1, or θ = 90° <br/> <img src=\"2018 Model III/utmephysics2018miiiq11s.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2018 Model III>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform bar AB is balanced on a knife-edge which is 60cm from B by a mass of 22g which hangs at C 10cm from A as illustrated in the diagram above. Calculate the mass of the bar.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">133.2g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.0g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model III/utmephysics2018miiiq12s.png\" style=\"position:relative;max-width:100%;\"/> <br/> Clockwise movement = Anticlockwise movement <br/> m × 10 = 22 × 30 <br/> m = 66.0g</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2018 Model III>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 400g moving round a circular track of radius 50cm with a velocity of 12m/s. The centripetal force on the object is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">110N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">115N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mass, m = 400g = 0.4 kg <br/> Radius, r = 50cm = 0.5m <br/> velocity, v = 12 m/s <br/> Centripetal force, F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.4 × 144<hr size=\"1\" />0.5</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = 115.2N ≈ 115N</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model III>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> A fixed mass of gas is heated at constant volume so that its Celsius temperature is doubled. The pressure of the gas </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is halved </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is more than doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases but is less than doubled</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure is directly proportional to the absolute, not the Celsius temperature. Thus  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273)<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> Hence P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is greater than one but less than 2</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model III>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of wave is emitted by a loud speaker?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Longitudinal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A loudspeaker emits sound waves, which are longitudinal waves. In longitudinal waves, the displacement of the medium is in the same direction as, or the opposite direction to, the direction of propagation of the wave. Hence, the correct answer is 'Longitudinal'.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2018 Model III>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following units is derived?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NKg is the unit of mass , m is the unit of lenght , k is unit of temperature and N is the unit of force. Amongst these, force is the only dervied quantity <br/> </div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS"}, {"id": "objective>Physics>2018 Model III>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ship travelling towards a cliff receives the echo of its whistle after 3.5s, a short while he receives it receives the echo after 2.5s. If the speed of sound in the air under the prevailing conditions is 250ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> how much closer to the cliff is the ship?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">121m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2d<hr size=\"1\" />t</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">250</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2d<hr size=\"1\" />3.5 - 2.5</td></tr></table></div> <br/> 250 = 2d <br/>  <br/> d = 125m</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2018 Model III>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body is projected horizontally with a velocity of 15m/s from a cliff of height 180m. What is the range of the body? <br/> [g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model III/eo5i53.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: R = UT ------ (1) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">2H<hr size=\"1\" />g</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">360<hr size=\"1\" />10</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> R = 15&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">36&nbsp;</span> = 15(6) = 90m <br/> </div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2018 Model III>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the period of oscillation of a body executing S.H.M whose angular velocity is 628 rad/s.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5ms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8ms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10ms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15ms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Angular Velocity, ω = 628rad/s <br/> Period, T = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2×3.142<hr size=\"1\" />628</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.28<hr size=\"1\" />628</td></tr></table></div> <br/> = 0.01m/s <br/> N.B: The unit is in ms <br/> ∴ 0.01m/s = 10ms</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2018 Model III>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ice at 0°C is added to 10kg of water at 50°C. If the final temperature of the water is 30°C, the mass of the ice added is  <br/>  <br/> (Latent heat of fusion of ice = 336,000 J/kg, specific heat capacity of water = 4200 J/kg.K)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.8kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.7kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.7kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat gained by the ice = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span>c(30 - 0) = 336,000m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> + (4,200 × 30)m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 462,000m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span>(J) <br/> Heat lost by water = 10(4200)(50 - 30) = 840,000J <br/> 462,000m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 840,000 or m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> = 1.8kg</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2018 Model III>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the tension in a sonometer is tripled, the ratio of the new frequency to the original frequency is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that; frequency F is directly proportional to the square root of tension, &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> F α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> The tension is trippled, i.e <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div> <br/> The ratio of the new frequrncy to the original frequency i.e <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div> <br/> </div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2018 Model III>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two bodies have masses in the ratio 3:1. They experience forces which imparts to them acceleration in the ratio 2:9 respectively. Find the ratio of forces the masses experienced.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />1</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />9</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Unknown</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3×2<hr size=\"1\" />1×9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td></tr></table></div></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2018 Model III>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour whose molecules are in dynamic equilibrium with those of its own liquid is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unsaturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gaseous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffused </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Such vapour is said to be saturated. That is, the rate of evaporation is equal to the rate of condensation</div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2018 Model III>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body can undergo the following types of motion except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">random</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">translational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All bodies can undergo random, rotational, and translational motion. However, relative motion is not a type of motion a body undergoes, but rather a way of describing motion in relation to a frame of reference. Therefore, a body cannot 'undergo' relative motion.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2018 Model III>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A horizontal force of 12N is applied to a body of mass 10kg which rests on a horizontal surface of coefficient of friction 0.1. The body will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accelerate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain at rest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">move with uniform speed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">first accelerate and then move with uniform speed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Limiting frictional force = μmg = 0.1(10)(10) = 10N <br/> Under an applied force of 12N, a net force of 2N acts on the body and causes it to accelerate. [If the applied force is less than 10N, the body will remain at rest].</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2018 Model III>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What must be connected between the points P and Q to establish a steady current through the incomplete circuit diagram illustrated above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fuse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammeter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Voltmeter</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A cell must be connected to establish a steady current through the incomplete circuit diagram illustrated above.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2018 Model III>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following concepts is a method of heat transfer that does not require a material medium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conduction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convention</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radiation is a method of heat transfer that does not require a material medium. It is the emission of energy as electromagnetic waves or as moving subatomic particles, especially high-energy particles that cause ionization. Unlike conduction and convection, radiation can occur in a vacuum, as with the heat from the sun.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2018 Model III>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formular for maximum power transfer of a cell whose e.m.f is E and internal resistance r is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/2r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/4r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/8r</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: E = v + Ir ------ (1) <br/> E = I(R + r) ------ (2) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td></tr></table></div> <br/> Recall: <br/> P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(R+r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">R</td></tr></table></div> <br/> For maximum power transfer <br/> R = r <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(r+r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(2r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4r</td></tr></table></div></div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2018 Model III>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A lamp is connected across a battery. A piece of low conductivity wire is now connected in series with it. The lamp will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glow brighter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glow dimmer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unaffected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quickly burn out</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low conductivity wire has a high resistance. Since this is connected in series with the lamp, current through the circuit is reduced (l = V/R) and the lamp glows dimmer. [What happens if the wire is connected in parallel with the lamp?]</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2018 Model III>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constant-volume gas thermometer operates under which gas law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Boyle's law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charles' law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Avogadro's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pressure law</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A constant-volume gas thermometer operates under the pressure law, which states that the pressure of a gas at constant volume is directly proportional to its temperature.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model III>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the maximum velocity of a particle undergoing circular motion such that the radius of the path is 75cm and its moving at 100 r.p.m</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span> = ? <br/> Radius, r = 75cm = 0.75m <br/> Frequency, f = 100rev per minutes <br/> We have to convert f to rev. per second  <br/> 100 rev → 1 minute  <br/> 100rev → 60 seconds  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />3</td><td style=\"text-align:center;\">Hz</td></tr></table></div> <br/> Recall: V = ωr -------- (1) <br/> ω = 2πf ----------- (2) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">5<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10π<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10π<hr size=\"1\" />3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.75</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10π<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5π</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">22<hr size=\"1\" />7</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> V = 7.86ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> ≈ 8.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model III>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force that tend to pull an object undergoing circular motion towards the centre is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centripetal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centrifugal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force that tends to pull an object undergoing circular motion towards the centre is the centripetal force, centrifugal force will pull it away from the centre.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model III>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A flask containing a volatile liquid at room temperature has the space above the liquid evacuated of all air and the valve closed. If the flask is now placed in a jar containing an ice-water mixture, the level of the liquid in the flask</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">first increases and then decreases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The space above the volatile liquid is filled with its vapour after the valve is closed. As the flask is placed in an ice-water mixture, the SVP of the liquid decreases, causing some vapour to condense and raise the level of liquid in the flask.</div>", "topic": "CHANGE OF STATE~~VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2018 Model III>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The barometric reading at a place is 73.5cm Hg. Calculate the pressure at a point 30m below the surface of water contained in a reservoir at the place. <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, density of mercury = 1.36 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, density of water = 1.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = hρg  <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">atm</span> = 0.735 × 13600 × 10 = 99960 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span> = 30 × 1000 × 10 = 3.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">atm</span> + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">water</span> = 99960 + 300000 <br/>  <br/> ∴ P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">total</span> = 399960 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> ≃ 4.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2018 Model III>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atmospheric pressure of air was determined to be 760mmHg by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Blaise pascal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Evangelista Torricelli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Johann Bernoulli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Galileo Galilei</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The atmospheric pressure of air was first accurately measured by Evangelista Torricelli, an Italian physicist and mathematician, in the 17th century. He invented the mercury barometer, an instrument that measures atmospheric pressure. The standard atmospheric pressure is defined as 760 mmHg at sea level at a temperature of 0 degrees Celsius.</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2018 Model III>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat reaches the food which is being cooked in a saucepan chiefly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conduction and convection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction and radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convection and radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction and diffusion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat flows in through the wall of the saucepan by conduction and to the different parts of the food by convection, involving the circulation of water and steam.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2018 Model III>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An iron spoon placed inside hot tea becomes hot. This heat transfer is due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convection</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An iron spoon placed inside hot tea becomes hot due to the conduction of heat from the tea through the surface of the spoon. This is possible because the material of the spoon is a good conductor of heat (iron).</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2018 Model III>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the length of a simple pendulum is halved, its frequency is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased by a factor of 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by a factor of 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased by a factor of &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by a factor of &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">k<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/2&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div></div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2018 Model III>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs correctly represents the relationship between the kinetic energy (K.E) and the displacement (d) from point of release of a swinging pendulum bob?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a swinging pendulum, at the point of rest, i.e at equilibruim, the K.E is maximum, when displaced so that it moves through a certain height h, the K.E decreases to minimum and then back to maximum as it comes back to the equilibrium position. <br/>  <br/>  <br/> The system contains both K.E and P.E at any instant in the motion. At the extreme positions, the P.E is equal to MGH. At B,  P.E=0, and K.E is maximum, K.E = 1/2 mv^2 <br/>  <br/> At the initial position, the K.E is zero, but as the acceleration of the pendulum Bob increases , the K.E increases and the reaches maximum at maximum displacement. Then when the pendulum Bob begins to decelerate, the K.E reduces till it becomes zero after deceleration <br/>  <br/> </div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2018 Model III>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following data is provided for water:  <br/> Specific heat capacity = 4.2 kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Specific latent heat of fusion = 335kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Specific latent heat of vaporization = 2260 kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> The heat required to change one kilogram of ice at 0°C to steam at 100°C is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3015kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2599.2kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">755kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">420kJ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat to melt 1kg of ice at 0°C <br/>  = mL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = (1)(335) = 335kJ <br/> Heat to raise the temperature from 0°C to 100°C <br/>  = mcθ = (1)(4.2)(100) = 420kJ <br/> Heat to vaporize 1kg of water at 100°C <br/>  = mL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> = (1)(2,260) = 2,260kJ <br/> Total heat required = 335 + 420 + 2,260 = 3,015kJ <br/> </div>", "topic": "HEAT ENERGY: CHANGE OF STATE"}];
